from flask import Flask, request, jsonify
from pymongo import MongoClient  # Python driver for MongoDB
import gridfs

app = Flask(__name__)
client = MongoClient('mongodb://localhost:27017/')  
db= client['content_management']    # create a db instance called content-manager. 
storage = gridfs.GridFS(db)            # Create an Grid Files System object for our database, which will allow us to handle and store files in MongoDB like documents (uplots).  

@app.route('/profile', methods=['POST'])   
def create_user():                          
  user = request.json                                              # Get the data sent by POST method on our web page from client's side, it is in json format .                     
